// Compute the day exactly 7 days ago in ET (workflow timezone)
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const y = sevenDaysAgo.getUTCFullYear();
const m = String(sevenDaysAgo.getUTCMonth() + 1).padStart(2, '0');
const d = String(sevenDaysAgo.getUTCDate()).padStart(2, '0');
const date_str = `${y}-${m}-${d}`;

return [{ json: {
  target_date: date_str,
  window_start: `${date_str}T00:00:00.000Z`,
  window_end: `${date_str}T23:59:59.999Z`,
  run_at: now.toISOString()
}}];

const order = $input.first().json;
const f = order.fields || order;

// Customer is a linked record on Orders → take linked Customer email lookup field if present;
// fall back to a `Customer email` rollup/lookup field (recommended Airtable schema).
const email = (f['Customer email'] || f['Email'] || '').toLowerCase().trim();
const first_name = f['First name'] || f['Customer first name'] || '';
const product_name = f['Product name'] || f['Product'] || 'STR Ledger workbook';
const product_sku = f['Product SKU'] || (Array.isArray(f['Product']) ? f['Product'][0] : '') || '';
const platform = (f['Platform'] || '').toLowerCase();
const order_id = f['Order ID'] || '';
const gumroad_product_permalink = f['Gumroad product permalink'] || '';
const etsy_listing_id = f['Etsy listing ID'] || '';

if (!email || !email.includes('@')) {
  throw new Error(`Order ${order_id} has no usable customer email`);
}
if (!['etsy', 'gumroad', 'is'].includes(platform)) {
  throw new Error(`Order ${order_id} has unsupported platform: ${platform}`);
}

let review_url;
if (platform === 'etsy') {
  review_url = etsy_listing_id
    ? `https://www.etsy.com/your/purchases?ref=review&listing_id=${etsy_listing_id}`
    : 'https://www.etsy.com/your/purchases';
} else if (platform === 'gumroad') {
  review_url = gumroad_product_permalink
    ? `${gumroad_product_permalink}#ratings`
    : 'https://gumroad.com/library';
} else {
  review_url = 'https://www.trustpilot.com/evaluate/thestrledger.com';
}

return [{ json: {
  order_record_id: order.id,
  order_id,
  email,
  first_name: first_name || 'there',
  product_name,
  product_sku,
  platform,
  review_url
}}];

const claude = $input.first().json;
const order = $node['Get Customer + Product'].json;
const body = (claude?.content?.[0]?.text || '').trim();
if (!body) throw new Error('Claude returned empty email body');

const subject = `Quick favor, ${order.first_name}?`;

return [{ json: {
  ...order,
  subject,
  email_body: body
}}];

// Runs after the SplitInBatches loop completes — aggregate all items
const items = $input.all();
const by_platform = { etsy: 0, gumroad: 0, is: 0 };
let total = 0;
for (const it of items) {
  const p = (it.json.platform || '').toLowerCase();
  if (by_platform[p] !== undefined) by_platform[p]++;
  total++;
}
return [{ json: {
  total_sent: total,
  by_platform,
  target_date: $node['Compute 7-Day Window'].json.target_date,
  run_at: new Date().toISOString()
}}];

const input = $input.first().json;
return [{ json: {
  timestamp: new Date().toISOString(),
  workflow: 'W13-review-request',
  node: $node.name || 'unknown',
  error_message: input.error?.message || JSON.stringify(input).slice(0, 500),
  payload: JSON.stringify(input).slice(0, 500),
  status: 'Open'
}}];
